import{_ as e,o as n,c as t,O as r}from"./chunks/framework.0d5b6918.js";const u=JSON.parse('{"title":"","description":"","frontmatter":{"aside":false,"outline":false,"lastUpdated":false},"headers":[],"relativePath":"en/materials/profile-pack.md","filePath":"en/materials/profile-pack.md","lastUpdated":1776344074000}'),s={name:"en/materials/profile-pack.md"};function i(c,a,l,d,o,p){return n(),t("div",null,a[0]||(a[0]=[r('<div class="brand-page-shell"><section class="brand-hero"><div><p class="brand-kicker">Material Guide</p><h1>Material Navigation</h1><div class="brand-hero__panel"><span class="brand-pill">Reading Paths</span><strong>ExecFabric&#39;s external materials cover platform positioning, kickoff options, delivery background, and public technical entry points. They can be entered through three paths: business judgment, cooperation judgment, and technical judgment.</strong><p>Different roles usually do not need to start from the same entry, but all of them can complete a basic judgment through a short path.</p></div><p class="brand-lead"> There are three more common reading patterns: <strong>judge platform value first, judge kickoff mode first, or judge delivery and technical background first.</strong> In the end, all three paths converge on the same question: whether the current project is suitable for phase-one advancement. </p><div class="brand-chip-list"><span class="brand-chip">business judgment</span><span class="brand-chip">cooperation evaluation</span><span class="brand-chip">technical judgment</span></div><div class="brand-actions"><a class="cta-button cta-button--brand" href="./pitch.html">View the pitch</a><a class="cta-button" href="./service-packages.html">View kickoff options</a><a class="cta-button" href="./founder-profile.html">View delivery background</a></div></div><div class="brand-hero__media brand-hero__media--compact"><div class="matrix-panel matrix-panel--contact"><div class="matrix-panel__hud"><span>EXECFABRIC // MATERIAL PACK</span><span>MAT 08</span></div><div class="matrix-panel__canvas"><div class="matrix-panel__trace matrix-panel__trace--top"></div><div class="matrix-panel__trace matrix-panel__trace--mid"></div><div class="matrix-panel__trace matrix-panel__trace--bottom"></div><div class="matrix-panel__stack"><span class="matrix-panel__line"><span class="matrix-panel__key">business</span><span class="matrix-panel__punct">:</span> <span class="matrix-panel__value matrix-panel__string">pitch</span><span class="matrix-panel__sep"> / </span><span class="matrix-panel__value matrix-panel__string">value</span></span><span class="matrix-panel__line"><span class="matrix-panel__key">cooperation</span><span class="matrix-panel__punct">:</span> <span class="matrix-panel__value matrix-panel__string">packages</span><span class="matrix-panel__sep"> / </span><span class="matrix-panel__value matrix-panel__string">delivery</span></span><span class="matrix-panel__line"><span class="matrix-panel__key">technical</span><span class="matrix-panel__punct">:</span> <span class="matrix-panel__value matrix-panel__string">background</span><span class="matrix-panel__sep"> / </span><span class="matrix-panel__value matrix-panel__string">github</span></span></div><div class="matrix-panel__callout">READ THE RIGHT PATH FIRST</div></div><div class="matrix-panel__footer"><span class="matrix-panel__tag"><span class="matrix-panel__key">goal</span><span class="matrix-panel__punct">:</span> <span class="matrix-panel__value">fast judgment</span></span><span class="matrix-panel__tag"><span class="matrix-panel__key">mode</span><span class="matrix-panel__punct">:</span> <span class="matrix-panel__value">3 paths</span></span><span class="matrix-panel__tag"><span class="matrix-panel__key">use</span><span class="matrix-panel__punct">:</span> <span class="matrix-panel__value">external reading</span></span></div></div></div></section><section class="brand-grid brand-grid--three"><article class="brand-card"><p class="brand-kicker">Path A</p><h2>Judge platform positioning first</h2><p>Best for business-side readers, project owners, and decision makers who are touching ExecFabric for the first time and need to answer &quot;what is it and why is it worth looking at?&quot;</p></article><article class="brand-card"><p class="brand-kicker">Path B</p><h2>Judge kickoff mode first</h2><p>Best for people already in a real project discussion and who need to judge how the project starts, how phase one closes, and whether the kickoff mode fits.</p></article><article class="brand-card"><p class="brand-kicker">Path C</p><h2>Judge delivery background first</h2><p>Best for technical leads and people who need to verify background, and want to judge delivery accumulation, project background, and public technical entry points first.</p></article></section><section class="brand-card"><p class="brand-kicker">Path A</p><h2>Business judgment path</h2><div class="brand-grid brand-grid--three"><article class="brand-card brand-card--nested"><h3>01. Platform positioning</h3><p><a href="./pitch.html">Pitch</a></p><p>Start with the platform definition, problem scenarios, and external narrative structure.</p></article><article class="brand-card brand-card--nested"><h3>02. Value judgment</h3><p><a href="./value.html">Value Framing</a></p><p>Then judge efficiency, controllability, and whether a pilot is worth starting.</p></article><article class="brand-card brand-card--nested"><h3>03. Product mainline</h3><p><a href="../product/index.html">Product Overview</a></p><p>If deeper understanding is needed, continue with the product mainline, capability structure, and roadmap direction.</p></article></div></section><section class="brand-card"><p class="brand-kicker">Path B</p><h2>Kickoff evaluation path</h2><div class="brand-grid brand-grid--three"><article class="brand-card brand-card--nested"><h3>01. Kickoff mode</h3><p><a href="./service-packages.html">Kickoff Options / Service Packages</a></p><p>Start with the project types that fit for kickoff, the standard service packages, and the phase-one closure mode.</p></article><article class="brand-card brand-card--nested"><h3>02. Delivery mode</h3><p><a href="../product/customer-flow.html">Customer Delivery &amp; Usage</a></p><p>Then continue with customer onboarding, delivery process, and the formal landing path.</p></article><article class="brand-card brand-card--nested"><h3>03. Onboarding preparation</h3><p><a href="../product/onboarding-checklist.html">Onboarding Checklist</a></p><p>When the evaluation needs to move, use it directly to align inputs, outputs, examples, and environment information.</p></article></div></section><section class="brand-card"><p class="brand-kicker">Path C</p><h2>Technical judgment path</h2><div class="brand-grid brand-grid--three"><article class="brand-card brand-card--nested"><h3>01. Background overview</h3><p><a href="./founder-card.html">Background Overview</a></p><p>Start with a quick look at the long-term mainline, project entry range, and current boundary.</p></article><article class="brand-card brand-card--nested"><h3>02. Delivery background</h3><p><a href="./founder-profile.html">Delivery Background and Project History</a></p><p>Then continue with project accumulation, governance awareness, and the source of the platform capability.</p></article><article class="brand-card brand-card--nested"><h3>03. Technical entry</h3><p><a href="https://github.com/zmx2321" target="_blank" rel="noreferrer">GitHub</a></p><p>If you want to verify engineering style, public code, and ongoing output further, continue into the public repositories.</p></article></div></section><section class="brand-card"><p class="brand-kicker">Freelance Use</p><h2>If you are evaluating cooperation</h2><div class="brand-grid brand-grid--two"><article class="brand-card brand-card--nested"><h3>Cooperation-material reading order</h3><p><a href="./freelance-home-structure.html">Three-Layer Cooperation Materials Structure and Suggested Reading Order</a></p><p>Helps you look at the background overview first, then verify projects and capabilities, and finally move into service packages and delivery boundary.</p></article><article class="brand-card brand-card--nested"><h3>Source and licensing boundary</h3><p><a href="./source-delivery-boundaries.html">Source Delivery and Licensing Boundary</a></p><p>Helps you distinguish quickly between standard delivery, private deployment, and source-code licensing.</p></article></div></section><section class="brand-grid brand-grid--two"><article class="brand-card"><p class="brand-kicker">Reading Advice</p><h2>It is not ideal to stop at only one entry</h2><ul class="brand-list"><li>Looking only at platform positioning without kickoff mode and delivery path.</li><li>Looking only at delivery background without product value and cooperation structure.</li><li>Looking only at public code without the project scenario and business boundary.</li><li>Reading one page and concluding too early, which makes it easy to miss key judgment information.</li></ul></article><article class="brand-card"><p class="brand-kicker">One-Line Rule</p><h2>The three shortest paths</h2><ul class="brand-list"><li>Want to judge platform positioning first: go to the Pitch page.</li><li>Want to judge kickoff mode first: go to Kickoff Options / Service Packages.</li><li>Want to judge delivery background first: go to Background Overview or Delivery Background.</li><li>After the first judgment is done, add the other two paths and the picture becomes more complete.</li></ul></article></section></div>',1)]))}const m=e(s,[["render",i]]);export{u as __pageData,m as default};
